def enhanced_heuristic(board: Board, boxes: tuple[Pos, ...]) -> int:
    """Greedy matching + mobility penalty (mirrors Rust enhanced_heuristic)."""
    base = greedy_matching(board, boxes)
    goal_set = frozenset(board.goals)
    box_set = frozenset(boxes)
    penalty = 0
    for bx in boxes:
        if bx in goal_set:
            continue
        blocked = 0
        for dx, dy in DIRECTIONS:
            nb = Pos(bx.x + dx, bx.y + dy)
            if nb in board.walls or nb in box_set:
                blocked += 1
        if blocked >= 3:
            penalty += 10
        elif blocked == 2:
            penalty += 2
    return base + penalty

def heuristic(board, boxes):
    """
    Admissible heuristic:
    1. Detect static dead squares (corner propagation). Any box on such a
       square makes the state unsolvable → return a large constant.
    2. Return the optimal (minimum‑sum) Manhattan assignment of boxes to goals,
       which is a classic lower‑bound on the remaining pushes.
    """
    # ---------- 1. static dead‑square detection ----------
    goal_set = frozenset(board.goals)
    walls = board.walls

    # initial corner dead squares (non‑goals)
    dead = set()
    for y in range(board.height):
        for x in range(board.width):
            p = Pos(x, y)
            if p in walls or p in goal_set:
                continue
            up = Pos(x, y - 1) in walls
            down = Pos(x, y + 1) in walls
            left = Pos(x - 1, y) in walls
            right = Pos(x + 1, y) in walls
            if (up and left) or (up and right) or (down and left) or (down and right):
                dead.add(p)

    # propagate: any non‑goal cell with three or more blocked neighbours is dead
    changed = True
    while changed:
        changed = False
        for y in range(board.height):
            for x in range(board.width):
                p = Pos(x, y)
                if p in walls or p in goal_set or p in dead:
                    continue
                blocked = 0
                for dx, dy in ((0, -1), (0, 1), (-1, 0), (1, 0)):
                    nb = Pos(x + dx, y + dy)
                    if nb in walls or nb in dead:
                        blocked += 1
                if blocked >= 3:
                    dead.add(p)
                    changed = True

    # if any box sits on a dead square, the state cannot be solved
    for bx in boxes:
        if bx in dead:
            return 10_000   # large admissible penalty

    # ---------- 2. optimal Manhattan matching ----------
    n = len(boxes)
    m = len(board.goals)
    # distance matrix
    dist = [[bx.manhattan(g) for g in board.goals] for bx in boxes]

    # DP over subsets of goals (bitmask). Works because n == m for typical levels.
    INF = 10 ** 9
    from functools import lru_cache

    @lru_cache(maxsize=None)
    def dp(i, mask):
        """minimum total distance for boxes[i:] given used goals mask."""
        if i == n:
            return 0
        best = INF
        for j in range(m):
            if not (mask & (1 << j)):
                cand = dist[i][j] + dp(i + 1, mask | (1 << j))
                if cand < best:
                    best = cand
        return best

    return dp(0, 0)

from __future__ import annotations
from collections import deque
from functools import lru_cache

# ---------- helper: reachable squares for a box (reverse push BFS) ----------
@lru_cache(maxsize=None)
def _push_reachable(walls: frozenset[Pos], goals: tuple[Pos, ...]) -> frozenset[Pos]:
    """Squares from which a box can be pushed to a goal, ignoring other boxes."""
    DIRS = [(0, -1), (1, 0), (0, 1), (-1, 0)]
    reachable: set[Pos] = set()
    q = deque(goals)               # start from goal squares (box already solved)

    while q:
        p = q.popleft()
        if p in reachable:
            continue
        reachable.add(p)

        for dx, dy in DIRS:
            # reverse a push: box was at `prev`, player stood at `player`
            prev = Pos(p.x - dx, p.y - dy)
            player = Pos(p.x - 2 * dx, p.y - 2 * dy)

            # both squares must be free of walls for the reverse move to be legal
            if prev in walls or player in walls:
                continue
            if prev not in reachable:
                q.append(prev)

    return frozenset(reachable)


